def validate_cart_items(cart_items):
    valid_items = []
    for item in cart_items:
        if item['available'] and item['quantity'] > 0:
            valid_items.append(item)
    return valid_items

def apply_discount_codes(cart_total, discount_codes, user):
    valid_discount = 0
    for code in discount_codes:
        if (code['type'] == 'general' or 
            (code['type'] == 'admin' and user['is_admin']) or 
            (code['type'] == 'tier' and code['tier'] == user['tier'])):
            valid_discount += cart_total * code['discount']
    return cart_total - valid_discount

def calculate_tax(cart_subtotal, tax_rate):
    return cart_subtotal * tax_rate

def process_payment(cart_total, payment_info):
    if payment_info['valid']:
        return True  # Simulate successful payment processing
    return False

def create_order_record(user, cart_items, final_total):
    order = {
        'user_id': user['id'],
        'items': cart_items,
        'total': final_total,
        'order_status': 'completed'
    }
    return order

def checkout(cart_items, discount_codes, user, tax_rate, payment_info):
    validated_items = validate_cart_items(cart_items)
    if not validated_items:
        return 'Cart validation failed'
    
    cart_subtotal = sum(item['price'] * item['quantity'] for item in validated_items)
    cart_subtotal = apply_discount_codes(cart_subtotal, discount_codes, user)
    
    tax_amount = calculate_tax(cart_subtotal, tax_rate)
    final_total = cart_subtotal + tax_amount
    
    if not process_payment(final_total, payment_info):
        return 'Payment processing failed'

    order_record = create_order_record(user, validated_items, final_total)
    return order_record

